const http = require('http');
const https = require('https');
const PORT = process.env.PORT || 3000;
const DASHBOARD = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>DropBot \u2014 AI Dropshipping Dashboard</title>\n<style>\n  :root {\n    --bg: #0a0a0f;\n    --surface: #13131a;\n    --surface2: #1c1c27;\n    --border: rgba(255,255,255,0.08);\n    --border2: rgba(255,255,255,0.14);\n    --text: #e8e8f0;\n    --muted: #7878a0;\n    --accent: #7c5cfc;\n    --accent2: #a78bfa;\n    --green: #22d3a0;\n    --amber: #f59e0b;\n    --red: #f87171;\n    --pink: #f472b6;\n    --radius: 12px;\n    --radius-sm: 8px;\n    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;\n  }\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n  body { background: var(--bg); color: var(--text); min-height: 100vh; }\n\n  .app { display: grid; grid-template-columns: 220px 1fr; min-height: 100vh; }\n\n  /* Sidebar */\n  .sidebar { background: var(--surface); border-right: 1px solid var(--border); padding: 24px 16px; display: flex; flex-direction: column; gap: 4px; }\n  .logo { display: flex; align-items: center; gap: 8px; padding: 0 8px 20px; border-bottom: 1px solid var(--border); margin-bottom: 12px; }\n  .logo-icon { width: 32px; height: 32px; background: var(--accent); border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 16px; }\n  .logo-text { font-size: 16px; font-weight: 600; letter-spacing: -0.3px; }\n  .logo-text span { color: var(--accent2); }\n  .nav-item { padding: 9px 12px; border-radius: var(--radius-sm); cursor: pointer; font-size: 13px; color: var(--muted); display: flex; align-items: center; gap: 8px; transition: all .15s; }\n  .nav-item:hover { background: var(--surface2); color: var(--text); }\n  .nav-item.active { background: rgba(124,92,252,0.15); color: var(--accent2); }\n  .nav-icon { font-size: 15px; width: 18px; text-align: center; }\n  .sidebar-section { font-size: 10px; color: var(--muted); letter-spacing: .8px; text-transform: uppercase; padding: 16px 12px 6px; }\n  .status-dot { width: 7px; height: 7px; border-radius: 50%; background: var(--green); margin-left: auto; animation: pulse 2s infinite; }\n  @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:.4} }\n\n  /* Main */\n  .main { overflow-y: auto; }\n  .topbar { padding: 20px 28px; border-bottom: 1px solid var(--border); display: flex; align-items: center; justify-content: space-between; background: var(--surface); position: sticky; top: 0; z-index: 10; }\n  .page-title { font-size: 18px; font-weight: 600; }\n  .page-sub { font-size: 12px; color: var(--muted); margin-top: 2px; }\n  .top-actions { display: flex; gap: 10px; align-items: center; }\n\n  .content { padding: 24px 28px; display: flex; flex-direction: column; gap: 24px; }\n\n  /* Cards */\n  .card { background: var(--surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 20px; }\n  .card-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 16px; }\n  .card-title { font-size: 13px; font-weight: 600; color: var(--muted); text-transform: uppercase; letter-spacing: .5px; }\n\n  /* Stats row */\n  .stats { display: grid; grid-template-columns: repeat(4, 1fr); gap: 14px; }\n  .stat { background: var(--surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 18px 20px; }\n  .stat-label { font-size: 11px; color: var(--muted); text-transform: uppercase; letter-spacing: .5px; margin-bottom: 8px; }\n  .stat-value { font-size: 26px; font-weight: 700; letter-spacing: -1px; }\n  .stat-change { font-size: 11px; margin-top: 4px; }\n  .stat-change.up { color: var(--green); }\n  .stat-change.down { color: var(--red); }\n\n  /* Config panel */\n  .config-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }\n  .field { display: flex; flex-direction: column; gap: 6px; }\n  .field label { font-size: 12px; color: var(--muted); font-weight: 500; }\n  .field input, .field select { background: var(--surface2); border: 1px solid var(--border); border-radius: var(--radius-sm); padding: 9px 12px; color: var(--text); font-size: 13px; outline: none; transition: border .15s; }\n  .field input:focus, .field select:focus { border-color: var(--accent); }\n  .field input::placeholder { color: var(--muted); }\n  .field.full { grid-column: 1/-1; }\n\n  /* Buttons */\n  .btn { padding: 9px 18px; border-radius: var(--radius-sm); border: none; cursor: pointer; font-size: 13px; font-weight: 500; transition: all .15s; display: inline-flex; align-items: center; gap: 6px; }\n  .btn-primary { background: var(--accent); color: #fff; }\n  .btn-primary:hover { background: #6b4ee8; }\n  .btn-secondary { background: var(--surface2); color: var(--text); border: 1px solid var(--border); }\n  .btn-secondary:hover { border-color: var(--border2); }\n  .btn-green { background: rgba(34,211,160,0.15); color: var(--green); border: 1px solid rgba(34,211,160,0.25); }\n  .btn-green:hover { background: rgba(34,211,160,0.25); }\n  .btn-sm { padding: 6px 12px; font-size: 12px; }\n  .btn:disabled { opacity: .45; cursor: not-allowed; }\n\n  /* Products table */\n  .products-list { display: flex; flex-direction: column; gap: 2px; }\n  .product-row { display: grid; grid-template-columns: 2fr 1fr 80px 90px 100px 120px; gap: 12px; align-items: center; padding: 12px 14px; border-radius: var(--radius-sm); border: 1px solid transparent; transition: all .15s; font-size: 13px; }\n  .product-row:hover { background: var(--surface2); border-color: var(--border); }\n  .product-row.header { color: var(--muted); font-size: 11px; text-transform: uppercase; letter-spacing: .5px; padding: 8px 14px; }\n  .product-name { font-weight: 500; }\n  .product-source { font-size: 11px; color: var(--muted); }\n  .score-bar { display: flex; align-items: center; gap: 8px; }\n  .score-fill { height: 4px; border-radius: 2px; flex: 1; background: var(--surface2); }\n  .score-inner { height: 100%; border-radius: 2px; }\n  .badge { padding: 3px 8px; border-radius: 4px; font-size: 11px; font-weight: 500; display: inline-block; }\n  .badge-green { background: rgba(34,211,160,0.15); color: var(--green); }\n  .badge-amber { background: rgba(245,158,11,0.15); color: var(--amber); }\n  .badge-red { background: rgba(248,113,113,0.15); color: var(--red); }\n  .badge-purple { background: rgba(124,92,252,0.15); color: var(--accent2); }\n\n  /* Log */\n  .log { background: #0d0d14; border: 1px solid var(--border); border-radius: var(--radius-sm); padding: 14px; font-family: 'SF Mono', 'Fira Code', monospace; font-size: 12px; max-height: 220px; overflow-y: auto; display: flex; flex-direction: column; gap: 4px; }\n  .log-entry { display: flex; gap: 10px; }\n  .log-time { color: var(--muted); flex-shrink: 0; }\n  .log-msg { }\n  .log-msg.ok { color: var(--green); }\n  .log-msg.info { color: var(--accent2); }\n  .log-msg.warn { color: var(--amber); }\n  .log-msg.err { color: var(--red); }\n\n  /* Telegram section */\n  .tg-cmds { display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; }\n  .tg-cmd { background: var(--surface2); border: 1px solid var(--border); border-radius: var(--radius-sm); padding: 12px 14px; cursor: pointer; transition: all .15s; }\n  .tg-cmd:hover { border-color: var(--accent); }\n  .tg-cmd-name { font-size: 13px; font-weight: 500; color: var(--accent2); margin-bottom: 2px; }\n  .tg-cmd-desc { font-size: 11px; color: var(--muted); }\n\n  /* Response area */\n  .response-area { background: var(--surface2); border: 1px solid var(--border); border-radius: var(--radius-sm); padding: 14px; font-size: 13px; line-height: 1.7; min-height: 100px; color: var(--text); white-space: pre-wrap; max-height: 320px; overflow-y: auto; }\n  .response-area.loading::after { content: '\u258b'; animation: blink .8s infinite; }\n  @keyframes blink { 50% { opacity: 0; } }\n  .spinner { display: inline-block; width: 14px; height: 14px; border: 2px solid var(--border2); border-top-color: var(--accent); border-radius: 50%; animation: spin .7s linear infinite; }\n  @keyframes spin { to { transform: rotate(360deg); } }\n\n  .two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }\n  .section-divider { border: none; border-top: 1px solid var(--border); margin: 4px 0; }\n\n  .progress-bar { height: 3px; background: var(--surface2); border-radius: 2px; overflow: hidden; margin-top: 6px; }\n  .progress-fill { height: 100%; background: var(--accent); border-radius: 2px; transition: width .4s; }\n\n  @media(max-width:900px) {\n    .app { grid-template-columns: 1fr; }\n    .sidebar { display: none; }\n    .stats { grid-template-columns: repeat(2,1fr); }\n    .config-grid { grid-template-columns: 1fr; }\n    .two-col { grid-template-columns: 1fr; }\n    .product-row { grid-template-columns: 1fr auto; }\n    .product-row > *:nth-child(n+3) { display: none; }\n  }\n</style>\n</head>\n<body>\n<div class=\"app\">\n\n  <!-- Sidebar -->\n  <aside class=\"sidebar\">\n    <div class=\"logo\">\n      <div class=\"logo-icon\">\ud83d\uded2</div>\n      <div class=\"logo-text\">Drop<span>Bot</span></div>\n    </div>\n    <div class=\"nav-item active\"><span class=\"nav-icon\">\ud83d\udcca</span>Dashboard <div class=\"status-dot\"></div></div>\n    <div class=\"nav-item\" onclick=\"showSection('find')\"><span class=\"nav-icon\">\ud83d\udd0d</span>Find products</div>\n    <div class=\"nav-item\" onclick=\"showSection('products')\"><span class=\"nav-icon\">\ud83d\udce6</span>My products</div>\n    <div class=\"sidebar-section\">Integrations</div>\n    <div class=\"nav-item\" onclick=\"showSection('shopify')\"><span class=\"nav-icon\">\ud83d\udecd\ufe0f</span>Shopify</div>\n    <div class=\"nav-item\" onclick=\"showSection('telegram')\"><span class=\"nav-icon\">\u2708\ufe0f</span>Telegram bot</div>\n    <div class=\"nav-item\" onclick=\"showSection('settings')\"><span class=\"nav-icon\">\u2699\ufe0f</span>Settings</div>\n  </aside>\n\n  <!-- Main content -->\n  <div class=\"main\">\n    <div class=\"topbar\">\n      <div>\n        <div class=\"page-title\" id=\"page-title\">Dashboard</div>\n        <div class=\"page-sub\" id=\"page-sub\">AI-powered TikTok \u2192 Shopify dropshipping</div>\n      </div>\n      <div class=\"top-actions\">\n        <button class=\"btn btn-secondary btn-sm\" onclick=\"runScan()\">\n          <span id=\"scan-icon\">\ud83d\udd04</span> Scan TikTok now\n        </button>\n        <button class=\"btn btn-primary btn-sm\" onclick=\"showSection('settings')\">\u2699\ufe0f Configure</button>\n      </div>\n    </div>\n\n    <div class=\"content\" id=\"content-root\">\n\n      <!-- Stats -->\n      <div class=\"stats\" id=\"section-dashboard\">\n        <div class=\"stat\">\n          <div class=\"stat-label\">Products found</div>\n          <div class=\"stat-value\" id=\"stat-found\">0</div>\n          <div class=\"stat-change up\" id=\"stat-found-ch\">\u2014</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"stat-label\">Published to Shopify</div>\n          <div class=\"stat-value\" id=\"stat-pub\">0</div>\n          <div class=\"stat-change up\" id=\"stat-pub-ch\">\u2014</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"stat-label\">Avg viral score</div>\n          <div class=\"stat-value\" id=\"stat-score\">\u2014</div>\n          <div class=\"stat-change\" id=\"stat-score-ch\">\u2014</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"stat-label\">Last scan</div>\n          <div class=\"stat-value\" style=\"font-size:16px;\" id=\"stat-last\">Never</div>\n          <div class=\"stat-change\" id=\"stat-last-ch\">Waiting for first run</div>\n        </div>\n      </div>\n\n      <!-- Find products -->\n      <div class=\"card\" id=\"section-find\">\n        <div class=\"card-header\">\n          <div class=\"card-title\">\ud83d\udd0d Find winning products</div>\n          <button class=\"btn btn-primary btn-sm\" id=\"find-btn\" onclick=\"findProducts()\">Run AI search</button>\n        </div>\n        <div class=\"config-grid\" style=\"margin-bottom:16px\">\n          <div class=\"field\">\n            <label>TikTok niche / keyword</label>\n            <input type=\"text\" id=\"niche-input\" placeholder=\"e.g. aesthetic room decor, kitchen gadgets\" />\n          </div>\n          <div class=\"field\">\n            <label>Min viral score to keep</label>\n            <select id=\"min-score\">\n              <option value=\"60\">60+ (recommended)</option>\n              <option value=\"70\">70+ (strict)</option>\n              <option value=\"50\">50+ (broad)</option>\n              <option value=\"40\">40+ (all results)</option>\n            </select>\n          </div>\n          <div class=\"field\">\n            <label>Max products per search</label>\n            <select id=\"max-products\">\n              <option value=\"5\">5 products</option>\n              <option value=\"3\">3 products</option>\n              <option value=\"10\">10 products</option>\n            </select>\n          </div>\n          <div class=\"field\">\n            <label>Auto-publish to Shopify if score \u2265</label>\n            <select id=\"auto-pub-threshold\">\n              <option value=\"0\">Disabled (manual only)</option>\n              <option value=\"80\">80+ (high confidence)</option>\n              <option value=\"70\">70+ (confident)</option>\n              <option value=\"60\">60+ (aggressive)</option>\n            </select>\n          </div>\n        </div>\n        <div id=\"find-response\" class=\"response-area\" style=\"display:none\"></div>\n        <div id=\"find-progress\" style=\"display:none\">\n          <div class=\"progress-bar\"><div class=\"progress-fill\" id=\"find-prog-fill\" style=\"width:0%\"></div></div>\n          <div style=\"font-size:12px;color:var(--muted);margin-top:6px\" id=\"find-prog-label\">Searching TikTok trends...</div>\n        </div>\n      </div>\n\n      <!-- Products list -->\n      <div class=\"card\" id=\"section-products\">\n        <div class=\"card-header\">\n          <div class=\"card-title\">\ud83d\udce6 Product pipeline</div>\n          <button class=\"btn btn-secondary btn-sm\" onclick=\"clearProducts()\">Clear all</button>\n        </div>\n        <div class=\"products-list\">\n          <div class=\"product-row header\">\n            <div>Product</div>\n            <div>Niche</div>\n            <div>Score</div>\n            <div>Margin</div>\n            <div>Status</div>\n            <div>Actions</div>\n          </div>\n          <div id=\"products-body\">\n            <div style=\"padding:28px;text-align:center;color:var(--muted);font-size:13px\">\n              No products yet. Run a search above to find trending items.\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- Two col: Shopify + Telegram -->\n      <div class=\"two-col\">\n\n        <!-- Shopify -->\n        <div class=\"card\" id=\"section-shopify\">\n          <div class=\"card-header\">\n            <div class=\"card-title\">\ud83d\udecd\ufe0f Shopify</div>\n            <span id=\"shopify-status\" class=\"badge badge-amber\">Not configured</span>\n          </div>\n          <div class=\"field\" style=\"margin-bottom:12px\">\n            <label>Shop domain</label>\n            <input type=\"text\" id=\"shopify-domain\" placeholder=\"yourstore.myshopify.com\" />\n          </div>\n          <div class=\"field\" style=\"margin-bottom:12px\">\n            <label>Admin API token</label>\n            <input type=\"password\" id=\"shopify-token\" placeholder=\"shpat_...\" />\n          </div>\n          <div style=\"display:flex;gap:8px\">\n            <button class=\"btn btn-secondary btn-sm\" onclick=\"testShopify()\">Test connection</button>\n            <button class=\"btn btn-green btn-sm\" onclick=\"saveShopify()\">Save</button>\n          </div>\n          <div id=\"shopify-log\" style=\"margin-top:12px;font-size:12px;color:var(--muted)\"></div>\n        </div>\n\n        <!-- Telegram -->\n        <div class=\"card\" id=\"section-telegram\">\n          <div class=\"card-header\">\n            <div class=\"card-title\">\u2708\ufe0f Telegram bot</div>\n            <span id=\"tg-status\" class=\"badge badge-amber\">Not configured</span>\n          </div>\n          <div class=\"field\" style=\"margin-bottom:12px\">\n            <label>Bot token (from @BotFather)</label>\n            <input type=\"password\" id=\"tg-token\" placeholder=\"1234567890:ABC...\" />\n          </div>\n          <div class=\"field\" style=\"margin-bottom:12px\">\n            <label>Your chat ID</label>\n            <input type=\"text\" id=\"tg-chatid\" placeholder=\"Get from @userinfobot\" />\n          </div>\n          <div class=\"field\" style=\"margin-bottom:12px\">\n            <label>Proxy server URL (optional \u2014 for local file use)</label>\n            <input type=\"text\" id=\"tg-proxy\" placeholder=\"https://your-railway-url.up.railway.app\" />\n          </div>\n          <div style=\"display:flex;gap:8px;margin-bottom:14px\">\n            <button class=\"btn btn-secondary btn-sm\" onclick=\"testTelegram()\">Send test message</button>\n            <button class=\"btn btn-green btn-sm\" onclick=\"saveTelegram()\">Save</button>\n          </div>\n          <div class=\"card-title\" style=\"margin-bottom:10px\">Bot commands</div>\n          <div class=\"tg-cmds\">\n            <div class=\"tg-cmd\" onclick=\"simulateTgCommand('/scan kitchen gadgets')\">\n              <div class=\"tg-cmd-name\">/scan [niche]</div>\n              <div class=\"tg-cmd-desc\">Find trending products</div>\n            </div>\n            <div class=\"tg-cmd\" onclick=\"simulateTgCommand('/products')\">\n              <div class=\"tg-cmd-name\">/products</div>\n              <div class=\"tg-cmd-desc\">List pipeline items</div>\n            </div>\n            <div class=\"tg-cmd\" onclick=\"simulateTgCommand('/publish best')\">\n              <div class=\"tg-cmd-name\">/publish [id]</div>\n              <div class=\"tg-cmd-desc\">Push to Shopify</div>\n            </div>\n            <div class=\"tg-cmd\" onclick=\"simulateTgCommand('/report')\">\n              <div class=\"tg-cmd-name\">/report</div>\n              <div class=\"tg-cmd-desc\">Daily summary</div>\n            </div>\n          </div>\n          <div id=\"tg-response\" class=\"response-area\" style=\"margin-top:12px;display:none;font-size:12px\"></div>\n        </div>\n      </div>\n\n      <!-- Log -->\n      <div class=\"card\" id=\"section-log\">\n        <div class=\"card-header\">\n          <div class=\"card-title\">Activity log</div>\n          <button class=\"btn btn-secondary btn-sm\" onclick=\"clearLog()\">Clear</button>\n        </div>\n        <div class=\"log\" id=\"activity-log\">\n          <div class=\"log-entry\"><span class=\"log-time\">\u2014</span><span class=\"log-msg info\">DropBot ready. Configure Shopify and Telegram, then run a product scan.</span></div>\n        </div>\n      </div>\n\n      <!-- Settings -->\n      <div class=\"card\" id=\"section-settings\" style=\"display:none\">\n        <div class=\"card-header\"><div class=\"card-title\">\u2699\ufe0f Settings</div></div>\n        <div style=\"font-size:13px;color:var(--muted);margin-bottom:16px\">All credentials are stored in your browser only and never sent anywhere except the services you configure.</div>\n        <div class=\"config-grid\">\n          <div class=\"field\">\n            <label>Auto-scan interval</label>\n            <select id=\"scan-interval\">\n              <option value=\"0\">Manual only</option>\n              <option value=\"3600\">Every hour</option>\n              <option value=\"21600\">Every 6 hours</option>\n              <option value=\"86400\">Daily</option>\n            </select>\n          </div>\n          <div class=\"field\">\n            <label>Default profit margin target (%)</label>\n            <input type=\"number\" id=\"margin-target\" value=\"40\" min=\"10\" max=\"90\" />\n          </div>\n          <div class=\"field\">\n            <label>Default product collection</label>\n            <input type=\"text\" id=\"shopify-collection\" placeholder=\"TikTok Trending\" />\n          </div>\n          <div class=\"field full\">\n            <label>Anthropic API key (for AI product search)</label>\n            <input type=\"password\" id=\"anthropic-key\" placeholder=\"sk-ant-...\" />\n            <div style=\"font-size:11px;color:var(--muted);margin-top:4px\">Get yours free at <a href=\"https://console.anthropic.com\" target=\"_blank\" style=\"color:var(--accent2)\">console.anthropic.com</a> \u2192 API Keys</div>\n          </div>\n          <div class=\"field\">\n            <label>Markup multiplier over supplier price</label>\n            <select id=\"markup\">\n              <option value=\"2.5\">2.5x</option>\n              <option value=\"3\">3x</option>\n              <option value=\"2\">2x</option>\n              <option value=\"4\">4x</option>\n            </select>\n          </div>\n        </div>\n        <div style=\"margin-top:16px\">\n          <button class=\"btn btn-primary\" onclick=\"saveSettings()\">Save settings</button>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</div>\n\n<script>\n// \u2500\u2500 State \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Config pre-loaded \u2014 edit these values directly!\nconst PRELOADED_CONFIG = {\n  shopifyDomain: '21e0ys-b4.myshopify.com',\n  shopifyToken: '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',\n  tgToken: '8868528681:AAEtOelQZbxtAwbRNa4S7ARky8oe172jdO4',\n  tgChatId: '7477483951',\n  tgProxy: 'https://dropbot-server-production-7e51.up.railway.app',\n  anthropicKey: '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',\n  markup: '2.5',\n  marginTarget: '40'\n};\n\nfunction safeGetStorage(key, fallback) {\n  try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : fallback; } catch(e) { return fallback; }\n}\nfunction safeSetStorage(key, value) {\n  try { localStorage.setItem(key, JSON.stringify(value)); } catch(e) {}\n}\n\nconst state = {\n  products: safeGetStorage('dropbot_products', []),\n  config: Object.assign({}, PRELOADED_CONFIG, safeGetStorage('dropbot_config', {})),\n  stats: { found: 0, published: 0 }\n};\n\n// \u2500\u2500 Boot \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.onload = () => {\n  loadConfig();\n  renderProducts();\n  updateStats();\n};\n\nfunction loadConfig() {\n  const c = state.config;\n  if (c.shopifyDomain) document.getElementById('shopify-domain').value = c.shopifyDomain;\n  if (c.shopifyToken) document.getElementById('shopify-token').value = c.shopifyToken;\n  if (c.tgToken) document.getElementById('tg-token').value = c.tgToken;\n  if (c.tgChatId) document.getElementById('tg-chatid').value = c.tgChatId;\n  if (c.tgProxy) document.getElementById('tg-proxy').value = c.tgProxy;\n  if (c.anthropicKey) document.getElementById('anthropic-key').value = c.anthropicKey;\n  if (c.markup) document.getElementById('markup').value = c.markup;\n  if (c.marginTarget) document.getElementById('margin-target').value = c.marginTarget;\n  updateConnectionBadges();\n}\n\nfunction updateConnectionBadges() {\n  const c = state.config;\n  const shopEl = document.getElementById('shopify-status');\n  const tgEl = document.getElementById('tg-status');\n  if (c.shopifyDomain && c.shopifyToken) {\n    shopEl.className = 'badge badge-green'; shopEl.textContent = 'Connected';\n  } else {\n    shopEl.className = 'badge badge-amber'; shopEl.textContent = 'Not configured';\n  }\n  if (c.tgToken && c.tgChatId) {\n    tgEl.className = 'badge badge-green'; tgEl.textContent = 'Active';\n  } else {\n    tgEl.className = 'badge badge-amber'; tgEl.textContent = 'Not configured';\n  }\n}\n\n// \u2500\u2500 Navigation \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction showSection(name) {\n  const titles = { find:'Find products', products:'Product pipeline', shopify:'Shopify', telegram:'Telegram bot', settings:'Settings', dashboard:'Dashboard' };\n  document.getElementById('page-title').textContent = titles[name] || name;\n  document.getElementById('section-settings').style.display = name === 'settings' ? '' : 'none';\n  document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));\n}\n\n// \u2500\u2500 Log \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction log(msg, type = 'info') {\n  const now = new Date().toLocaleTimeString();\n  const el = document.getElementById('activity-log');\n  const row = document.createElement('div');\n  row.className = 'log-entry';\n  row.innerHTML = `<span class=\"log-time\">${now}</span><span class=\"log-msg ${type}\">${msg}</span>`;\n  el.appendChild(row);\n  el.scrollTop = el.scrollHeight;\n}\nfunction clearLog() { document.getElementById('activity-log').innerHTML = ''; }\n\n// \u2500\u2500 Stats \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction updateStats() {\n  const products = state.products;\n  document.getElementById('stat-found').textContent = products.length;\n  const published = products.filter(p => p.status === 'published').length;\n  document.getElementById('stat-pub').textContent = published;\n  const scores = products.map(p => p.score).filter(Boolean);\n  document.getElementById('stat-score').textContent = scores.length ? Math.round(scores.reduce((a,b)=>a+b)/scores.length) : '\u2014';\n  if (state.lastScan) {\n    document.getElementById('stat-last').textContent = state.lastScan;\n    document.getElementById('stat-last-ch').textContent = 'Scan complete';\n  }\n}\n\n// \u2500\u2500 Products \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction saveProducts() {\n  safeSetStorage('dropbot_products', state.products);\n  updateStats();\n}\n\nfunction clearProducts() {\n  state.products = [];\n  saveProducts();\n  renderProducts();\n  log('Product pipeline cleared', 'warn');\n}\n\nfunction renderProducts() {\n  const body = document.getElementById('products-body');\n  if (!state.products.length) {\n    body.innerHTML = '<div style=\"padding:28px;text-align:center;color:var(--muted);font-size:13px\">No products yet. Run a search above to find trending items.</div>';\n    return;\n  }\n  body.innerHTML = state.products.map((p, i) => {\n    const scoreColor = p.score >= 80 ? '#22d3a0' : p.score >= 60 ? '#f59e0b' : '#f87171';\n    const statusBadge = p.status === 'published' ? '<span class=\"badge badge-green\">Published</span>'\n      : p.status === 'publishing' ? '<span class=\"badge badge-purple\">Publishing...</span>'\n      : '<span class=\"badge badge-amber\">Ready</span>';\n    return `<div class=\"product-row\">\n      <div>\n        <div class=\"product-name\">${p.name}</div>\n        <div class=\"product-source\">${p.supplier || 'AliExpress'} \u00b7 $${p.supplierPrice || '?'}</div>\n      </div>\n      <div style=\"font-size:12px;color:var(--muted)\">${p.niche || '\u2014'}</div>\n      <div class=\"score-bar\">\n        <div style=\"font-size:13px;font-weight:600;color:${scoreColor};min-width:28px\">${p.score}</div>\n        <div class=\"score-fill\"><div class=\"score-inner\" style=\"width:${p.score}%;background:${scoreColor}\"></div></div>\n      </div>\n      <div style=\"font-size:13px;color:var(--green)\">${p.margin ? p.margin+'%' : '\u2014'}</div>\n      <div>${statusBadge}</div>\n      <div style=\"display:flex;gap:6px\">\n        ${p.status !== 'published' ? `<button class=\"btn btn-green btn-sm\" onclick=\"publishProduct(${i})\">Publish</button>` : ''}\n        <button class=\"btn btn-secondary btn-sm\" onclick=\"analyzeProduct(${i})\">Analyze</button>\n      </div>\n    </div>`;\n  }).join('');\n}\n\n// \u2500\u2500 Claude AI calls \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function callClaude(prompt, systemPrompt, onChunk) {\n  const apiKey = state.config.anthropicKey;\n  const proxy = state.config.tgProxy;\n  if (!apiKey) throw new Error('No Anthropic API key \u2014 go to Settings and add your key from console.anthropic.com');\n  if (!proxy) throw new Error('No proxy server URL \u2014 go to Telegram bot section and add your Railway URL');\n\n  // Use Railway proxy to avoid CORS\n  const proxyUrl = `${proxy.replace(/\\/$/, '')}/ai`;\n  const resp = await fetch(proxyUrl, {\n    method: 'POST',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({\n      apiKey,\n      system: systemPrompt || 'You are DropBot, an expert AI dropshipping assistant. Be concise and specific. Always respond with actionable data.',\n      prompt\n    })\n  });\n  if (!resp.ok) throw new Error(`Proxy error: ${resp.status}`);\n  const data = await resp.json();\n  if (data.error) throw new Error(data.error);\n  const text = data.content?.[0]?.text || '';\n  if (onChunk) onChunk(text);\n  return text;\n  // dummy to satisfy original flow\n  \n\n// \u2500\u2500 Find Products \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function findProducts() {\n  const niche = document.getElementById('niche-input').value.trim() || 'viral home gadgets';\n  const minScore = parseInt(document.getElementById('min-score').value);\n  const maxP = parseInt(document.getElementById('max-products').value);\n  const autoThreshold = parseInt(document.getElementById('auto-pub-threshold').value);\n\n  const btn = document.getElementById('find-btn');\n  const resp = document.getElementById('find-response');\n  const prog = document.getElementById('find-progress');\n  const progFill = document.getElementById('find-prog-fill');\n  const progLabel = document.getElementById('find-prog-label');\n\n  btn.disabled = true;\n  btn.innerHTML = '<span class=\"spinner\"></span> Searching...';\n  resp.style.display = 'block';\n  resp.className = 'response-area loading';\n  resp.textContent = '';\n  prog.style.display = 'block';\n  progFill.style.width = '15%';\n  progLabel.textContent = 'Asking Claude to research TikTok trends...';\n\n  log(`Starting product search for niche: \"${niche}\"`, 'info');\n\n  try {\n    progFill.style.width = '40%';\n    progLabel.textContent = 'Analyzing viral products...';\n\n    const systemPrompt = `You are DropBot, an expert AI dropshipping product researcher. \nYou specialize in finding viral TikTok products for Shopify dropshipping.\nWhen asked to find products, respond with a JSON array only (no markdown, no explanation before or after).\nEach product object must have these exact fields:\n- name: product name (string)\n- niche: category (string)  \n- viralScore: 0-100 score based on TikTok virality potential (number)\n- supplierPrice: estimated AliExpress price in USD (number)\n- sellPrice: recommended sell price in USD (number)\n- margin: profit margin percent (number)\n- whyViral: 1-2 sentence reason this would go viral on TikTok (string)\n- targetAudience: who buys this (string)\n- shopifyTitle: optimized product title for Shopify (string)\n- shopifyDescription: 80-word Shopify product description (string)\n- keywords: 5 SEO keywords as array (array of strings)`;\n\n    const prompt = `Find ${maxP} winning dropshipping products in this niche: \"${niche}\".\nThese should be products currently trending or likely to go viral on TikTok.\nFocus on items that are:\n- Easy to ship (not fragile, not oversized)\n- Have strong visual/demo appeal for TikTok videos\n- Estimated AliExpress price $2-$25\n- High perceived value for markup\n- Not saturated (avoid phone cases, basic LED strips)\nOnly return products with viralScore >= ${minScore}.\nReturn ONLY a valid JSON array.`;\n\n    let rawText = '';\n    await callClaude(prompt, systemPrompt, (partial) => {\n      resp.className = 'response-area';\n      resp.textContent = partial;\n      rawText = partial;\n    });\n\n    progFill.style.width = '85%';\n    progLabel.textContent = 'Parsing results...';\n\n    // Parse JSON\n    let products = [];\n    try {\n      const match = rawText.match(/\\[[\\s\\S]*\\]/);\n      if (match) products = JSON.parse(match[0]);\n    } catch (e) {\n      log('JSON parse warning, using raw response', 'warn');\n    }\n\n    progFill.style.width = '100%';\n    progLabel.textContent = `Found ${products.length} products!`;\n\n    if (products.length > 0) {\n      resp.textContent = `\u2705 Found ${products.length} trending products for \"${niche}\":\\n\\n` +\n        products.map(p => `\u2022 ${p.name} (Score: ${p.viralScore}/100) \u2014 $${p.supplierPrice} \u2192 $${p.sellPrice} (${p.margin}% margin)\\n  ${p.whyViral}`).join('\\n\\n');\n\n      // Add to state\n      products.forEach(p => {\n        state.products.unshift({\n          name: p.shopifyTitle || p.name,\n          niche: p.niche,\n          score: p.viralScore,\n          supplierPrice: p.supplierPrice,\n          sellPrice: p.sellPrice,\n          margin: p.margin,\n          status: 'ready',\n          supplier: 'AliExpress',\n          description: p.shopifyDescription,\n          keywords: p.keywords,\n          whyViral: p.whyViral,\n          targetAudience: p.targetAudience,\n          rawData: p\n        });\n      });\n\n      saveProducts();\n      renderProducts();\n      state.lastScan = new Date().toLocaleTimeString();\n      updateStats();\n      log(`Added ${products.length} products from \"${niche}\" search`, 'ok');\n\n      // Auto-publish if threshold set\n      if (autoThreshold > 0) {\n        const toPublish = state.products.filter(p => p.score >= autoThreshold && p.status === 'ready');\n        if (toPublish.length) {\n          log(`Auto-publish threshold ${autoThreshold}: ${toPublish.length} products qualify`, 'info');\n          toPublish.forEach((_, i) => {\n            const idx = state.products.findIndex(p => p.score >= autoThreshold && p.status === 'ready');\n            if (idx !== -1) setTimeout(() => publishProduct(idx), i * 1500);\n          });\n        }\n      }\n\n      // Send Telegram notification\n      sendTelegramNotification(`\ud83d\udd0d *DropBot scan complete*\\n\\nNiche: ${niche}\\nFound: ${products.length} products\\nTop pick: *${products[0].name}* (Score: ${products[0].viralScore})\\n\\nType /products to see all`);\n    } else {\n      resp.textContent = '\u26a0\ufe0f No products matched your criteria. Try a broader niche or lower the minimum score.';\n      log('No products found matching criteria', 'warn');\n    }\n\n  } catch (err) {\n    resp.className = 'response-area';\n    resp.textContent = `\u274c Error: ${err.message}\\n\\nMake sure you're running this on claude.ai where the API is available.`;\n    log(`Search error: ${err.message}`, 'err');\n  } finally {\n    btn.disabled = false;\n    btn.innerHTML = 'Run AI search';\n    setTimeout(() => { prog.style.display = 'none'; }, 2000);\n  }\n}\n\n// \u2500\u2500 Publish to Shopify \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function publishProduct(idx) {\n  const product = state.products[idx];\n  if (!product) return;\n  const { shopifyDomain, shopifyToken } = state.config;\n\n  if (!shopifyDomain || !shopifyToken) {\n    log('Shopify not configured \u2014 configure in Settings', 'warn');\n    alert('Please configure your Shopify store first (scroll down to the Shopify card).');\n    return;\n  }\n\n  state.products[idx].status = 'publishing';\n  renderProducts();\n  log(`Publishing \"${product.name}\" to Shopify...`, 'info');\n\n  try {\n    const payload = {\n      product: {\n        title: product.name,\n        body_html: `<p>${product.description || ''}</p>`,\n        vendor: 'DropBot',\n        product_type: product.niche || 'General',\n        tags: (product.keywords || []).join(', '),\n        variants: [{\n          price: product.sellPrice?.toString() || '29.99',\n          requires_shipping: true,\n          taxable: true\n        }]\n      }\n    };\n\n    const res = await fetch(`https://${shopifyDomain}/admin/api/2024-01/products.json`, {\n      method: 'POST',\n      headers: {\n        'Content-Type': 'application/json',\n        'X-Shopify-Access-Token': shopifyToken\n      },\n      body: JSON.stringify(payload)\n    });\n\n    if (res.ok) {\n      const data = await res.json();\n      state.products[idx].status = 'published';\n      state.products[idx].shopifyId = data.product?.id;\n      saveProducts();\n      renderProducts();\n      log(`\u2705 \"${product.name}\" published to Shopify (ID: ${data.product?.id})`, 'ok');\n      sendTelegramNotification(`\u2705 *Published to Shopify*\\n\\n${product.name}\\nPrice: $${product.sellPrice}\\nShopify ID: ${data.product?.id}`);\n    } else {\n      const errBody = await res.text();\n      throw new Error(`Shopify API ${res.status}: ${errBody.slice(0,200)}`);\n    }\n  } catch (err) {\n    state.products[idx].status = 'ready';\n    saveProducts();\n    renderProducts();\n    log(`Shopify publish failed: ${err.message}`, 'err');\n    if (err.message.includes('CORS') || err.message.includes('fetch')) {\n      log('Tip: Shopify API requires a backend proxy in production (CORS)', 'warn');\n    }\n  }\n}\n\n// \u2500\u2500 Analyze Product \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function analyzeProduct(idx) {\n  const product = state.products[idx];\n  const resp = document.getElementById('find-response');\n  resp.style.display = 'block';\n  resp.className = 'response-area loading';\n  resp.textContent = '';\n\n  log(`Analyzing \"${product.name}\"...`, 'info');\n\n  try {\n    await callClaude(\n      `Give me a detailed dropshipping analysis for: \"${product.name}\"\\nViral score: ${product.score}/100\\nTarget: ${product.targetAudience || 'general'}\\n\\nInclude: TikTok video ideas, best ad angles, potential issues, pricing strategy, and estimated conversion rate.`,\n      'You are DropBot, a dropshipping expert. Be specific, practical, and concise. Use bullet points.',\n      (partial) => {\n        resp.className = 'response-area';\n        resp.textContent = partial;\n      }\n    );\n    log(`Analysis complete for \"${product.name}\"`, 'ok');\n  } catch (err) {\n    resp.textContent = `Error: ${err.message}`;\n    log(`Analysis error: ${err.message}`, 'err');\n  }\n}\n\n// \u2500\u2500 Run Scan (quick dashboard button) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function runScan() {\n  const niche = document.getElementById('niche-input').value.trim() || 'viral trending products';\n  document.getElementById('scan-icon').textContent = '\u23f3';\n  log('Quick scan initiated...', 'info');\n  await findProducts();\n  document.getElementById('scan-icon').textContent = '\ud83d\udd04';\n}\n\n// \u2500\u2500 Shopify Config \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction saveShopify() {\n  state.config.shopifyDomain = document.getElementById('shopify-domain').value.trim();\n  state.config.shopifyToken = document.getElementById('shopify-token').value.trim();\n  safeSetStorage('dropbot_config', state.config);\n  updateConnectionBadges();\n  document.getElementById('shopify-log').textContent = '\u2705 Saved';\n  log('Shopify credentials saved', 'ok');\n  setTimeout(() => { document.getElementById('shopify-log').textContent = ''; }, 3000);\n}\n\nasync function testShopify() {\n  const domain = document.getElementById('shopify-domain').value.trim();\n  const token = document.getElementById('shopify-token').value.trim();\n  const logEl = document.getElementById('shopify-log');\n  if (!domain || !token) { logEl.textContent = '\u26a0\ufe0f Enter domain and token first'; return; }\n  logEl.textContent = 'Testing...';\n  try {\n    const res = await fetch(`https://${domain}/admin/api/2024-01/shop.json`, {\n      headers: { 'X-Shopify-Access-Token': token }\n    });\n    if (res.ok) {\n      const data = await res.json();\n      logEl.style.color = 'var(--green)';\n      logEl.textContent = `\u2705 Connected to: ${data.shop?.name}`;\n      log(`Shopify connected: ${data.shop?.name}`, 'ok');\n    } else {\n      logEl.style.color = 'var(--red)';\n      logEl.textContent = `\u274c Error ${res.status} \u2014 check your token`;\n    }\n  } catch (err) {\n    logEl.style.color = 'var(--amber)';\n    logEl.textContent = `\u26a0\ufe0f CORS blocked in browser \u2014 connection may still work server-side`;\n    log('Shopify test blocked by CORS (normal in browser)', 'warn');\n  }\n}\n\n// \u2500\u2500 Telegram Config \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction saveTelegram() {\n  state.config.tgToken = document.getElementById('tg-token').value.trim();\n  state.config.tgChatId = document.getElementById('tg-chatid').value.trim();\n  state.config.tgProxy = document.getElementById('tg-proxy').value.trim();\n  safeSetStorage('dropbot_config', state.config);\n  updateConnectionBadges();\n  log('Telegram credentials saved', 'ok');\n}\n\nasync function testTelegram() {\n  const { tgToken, tgChatId, tgProxy } = state.config;\n  if (!tgToken || !tgChatId) { log('Save Telegram credentials first', 'warn'); return; }\n  const msg = 'DropBot connected! Your AI dropshipping assistant is ready.';\n  if (tgProxy) {\n    try {\n      const proxyUrl = `${tgProxy.replace(/\\/$/, '')}/telegram?token=${encodeURIComponent(tgToken)}&chat_id=${encodeURIComponent(tgChatId)}&text=${encodeURIComponent(msg)}`;\n      const res = await fetch(proxyUrl);\n      const data = await res.json();\n      if (data.ok) { log('Test message sent - check Telegram!', 'ok'); return; }\n    } catch(e) { log('Proxy error: ' + e.message, 'err'); }\n  }\n  const url = `https://api.telegram.org/bot${tgToken}/sendMessage?chat_id=${encodeURIComponent(tgChatId)}&text=${encodeURIComponent(msg)}`;\n  try { await fetch(url, { mode: 'no-cors' }); } catch(e) { new Image().src = url; }\n  log('Test message sent - check Telegram!', 'ok');\n}\n\nasync function sendTelegramNotification(text) {\n  const { tgToken, tgChatId, tgProxy } = state.config;\n  if (!tgToken || !tgChatId) return;\n  if (tgProxy) {\n    try {\n      const proxyUrl = `${tgProxy.replace(/\\/$/, '')}/telegram?token=${encodeURIComponent(tgToken)}&chat_id=${encodeURIComponent(tgChatId)}&text=${encodeURIComponent(text)}`;\n      const res = await fetch(proxyUrl);\n      const data = await res.json();\n      if (data.ok) { log('Telegram notification sent', 'ok'); return; }\n    } catch(e) {}\n  }\n  try {\n    const url = `https://api.telegram.org/bot${tgToken}/sendMessage?chat_id=${encodeURIComponent(tgChatId)}&text=${encodeURIComponent(text)}&parse_mode=Markdown`;\n    await fetch(url, { method: 'GET', mode: 'no-cors' });\n    log('Telegram notification sent', 'ok');\n  } catch (err) {\n    try {\n      const url = `https://api.telegram.org/bot${tgToken}/sendMessage?chat_id=${encodeURIComponent(tgChatId)}&text=${encodeURIComponent(text)}`;\n      new Image().src = url;\n      log('Telegram notification sent (fallback)', 'ok');\n    } catch(e) { log('Telegram error: ' + e.message, 'err'); }\n  }\n}\n\nasync function simulateTgCommand(cmd) {\n  const resp = document.getElementById('tg-response');\n  resp.style.display = 'block';\n  resp.className = 'response-area loading';\n  resp.textContent = '';\n  log(`Telegram command: ${cmd}`, 'info');\n\n  let prompt = '';\n  if (cmd.startsWith('/scan')) {\n    const niche = cmd.replace('/scan', '').trim() || 'trending products';\n    prompt = `You are DropBot responding to a Telegram /scan command for niche: \"${niche}\". List 3 top trending products with scores, supplier price, sell price, and one-line reason. Format for Telegram: use emojis, keep it brief.`;\n  } else if (cmd === '/products') {\n    if (!state.products.length) {\n      resp.className = 'response-area';\n      resp.textContent = '\ud83d\udce6 No products in pipeline yet.\\nUse /scan [niche] to find products.';\n      return;\n    }\n    resp.className = 'response-area';\n    resp.textContent = '\ud83d\udce6 *Your product pipeline:*\\n\\n' + state.products.slice(0,5).map((p,i) =>\n      `${i+1}. ${p.name}\\n   Score: ${p.score}/100 | Margin: ${p.margin}% | Status: ${p.status}`\n    ).join('\\n\\n');\n    return;\n  } else if (cmd === '/report') {\n    prompt = `You are DropBot. Generate a brief daily dropshipping report for Telegram. Mention: market trends today, best niches to target, quick tip. Keep it under 150 words. Use emojis.`;\n  } else if (cmd.startsWith('/publish')) {\n    resp.className = 'response-area';\n    resp.textContent = state.products.length ?\n      `\ud83d\ude80 Publishing \"${state.products[0].name}\" to Shopify...\\nUse the dashboard to publish products directly.` :\n      '\u26a0\ufe0f No products to publish. Run /scan first.';\n    return;\n  }\n\n  try {\n    await callClaude(prompt, 'You are DropBot, a Telegram bot for dropshipping. Be brief, use emojis, format for mobile.', (partial) => {\n      resp.className = 'response-area';\n      resp.textContent = partial;\n    });\n  } catch (err) {\n    resp.textContent = `Error: ${err.message}`;\n  }\n}\n\n// \u2500\u2500 Settings \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction saveSettings() {\n  state.config.markup = document.getElementById('markup').value;\n  state.config.marginTarget = document.getElementById('margin-target').value;\n  state.config.collection = document.getElementById('shopify-collection').value;\n  state.config.anthropicKey = document.getElementById('anthropic-key').value.trim();\n  safeSetStorage('dropbot_config', state.config);\n  log('Settings saved', 'ok');\n  document.getElementById('section-settings').style.display = 'none';\n}\n</script>\n</body>\n</html>\n";

function sendJSON(res, status, data) {
  res.writeHead(status, { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Methods': 'GET, POST, OPTIONS', 'Access-Control-Allow-Headers': 'Content-Type' });
  res.end(JSON.stringify(data));
}
function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({ raw: data }); }});
    }).on('error', reject);
  });
}
function httpsPost(hostname, path, headers, bodyObj) {
  return new Promise((resolve, reject) => {
    const bodyStr = JSON.stringify(bodyObj);
    const req = https.request({ hostname, path, method: 'POST', headers: { ...headers, 'Content-Length': Buffer.byteLength(bodyStr) } }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({ raw: data }); }});
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}
function readBody(req) {
  return new Promise((resolve) => { let body = ''; req.on('data', chunk => body += chunk); req.on('end', () => resolve(body)); });
}
const server = http.createServer(async (req, res) => {
  if (req.method === 'OPTIONS') { res.writeHead(204, { 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Methods': 'GET, POST, OPTIONS', 'Access-Control-Allow-Headers': 'Content-Type' }); res.end(); return; }
  const url = new URL(req.url, `http://localhost:${PORT}`);
  if (url.pathname === '/') { res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' }); res.end(DASHBOARD); return; }
  if (url.pathname === '/health') return sendJSON(res, 200, { status: 'DropBot server running' });
  if (url.pathname === '/telegram') {
    const token = url.searchParams.get('token'), chat_id = url.searchParams.get('chat_id'), text = url.searchParams.get('text');
    if (!token || !chat_id || !text) return sendJSON(res, 400, { error: 'Missing params' });
    try { return sendJSON(res, 200, await httpsGet(`https://api.telegram.org/bot${token}/sendMessage?chat_id=${encodeURIComponent(chat_id)}&text=${encodeURIComponent(text)}&parse_mode=Markdown`)); }
    catch(err) { return sendJSON(res, 500, { error: err.message }); }
  }
  if (url.pathname === '/ai' && req.method === 'POST') {
    try {
      const { apiKey, system, prompt } = JSON.parse(await readBody(req));
      if (!apiKey) return sendJSON(res, 400, { error: 'Missing apiKey' });
      return sendJSON(res, 200, await httpsPost('api.anthropic.com', '/v1/messages', { 'Content-Type': 'application/json', 'x-api-key': apiKey, 'anthropic-version': '2023-06-01' }, { model: 'claude-sonnet-4-20250514', max_tokens: 1500, system: system || 'You are DropBot.', messages: [{ role: 'user', content: prompt }] }));
    } catch(err) { return sendJSON(res, 500, { error: err.message }); }
  }
  sendJSON(res, 404, { error: 'Not found' });
});
server.listen(PORT, () => console.log(`DropBot on port ${PORT}`));
